export class Cart {
  add(item: CartItem) {
    return new Cart([...this.items, item]);
  }
}

export class Coupon {
  apply(total: Money) {
    return total.discount(this.percentage);
  }
}

export interface CartPort {
  load(): Promise<Cart>;
  save(cart: Cart): Promise<void>;
}

export class AddToCart {
  constructor(private cartPort: CartPort) {}

  execute(item: CartItem) {
    return this.cartPort.add(item);
  }
}

export class ApplyCoupon {
  constructor(private coupons: CouponPort, private cart: CartPort) {}
  async execute(code: string) {
    const coupon = await this.coupons.find(code);
    return this.cart.apply(coupon);
  }
}

@Injectable()
export class HttpCartAdapter implements CartPort {
  load() { return firstValueFrom(this.http.get<Cart>('/api/cart')); }
  save(cart: Cart) { return firstValueFrom(this.http.put<void>('/api/cart', cart)); }
}

export class LocalCartAdapter implements CartPort {
  load() { return Promise.resolve(JSON.parse(localStorage.getItem('cart') ?? '{}')); }
  save(cart: Cart) { localStorage.setItem('cart', JSON.stringify(cart)); return Promise.resolve(); }
}

@Component({ templateUrl: './cart.page.html' })
export class CartPage {
  addToCart = inject(AddToCart);
}
